  1→const DEFAULT_CANVAS_DOC = {
  2→    version: 1,
  3→    meta: {
  4→        aspectRatio: '1:1',
  5→        gridEnabled: true,
  6→        theme: 'light'
  7→    },
  8→    snippets: [],
  9→    images: []
 10→};
 11→
 12→const isPlainObject = (value) => value && typeof value === 'object' && !Array.isArray(value);
 13→
 14→const normalizeSnippet = (snippet, index) => {
 15→    if(!isPlainObject(snippet)){
 16→        return null;
 17→    }
 18→
 19→    const text = typeof snippet.text === 'string' ? snippet.text : '';
 20→    const parsedX = Number(snippet.x);
 21→    const parsedY = Number(snippet.y);
 22→    const parsedRotation = Number(snippet.rotation);
 23→    const parsedZIndex = Number(snippet.zIndex);
 24→    const parsedScaleX = Number(snippet.scaleX);
 25→    const parsedSizeScale = Number(snippet.sizeScale);
 26→
 27→    return {
 28→        id: typeof snippet.id === 'string' && snippet.id ? snippet.id : `snippet-${index + 1}`,
 29→        text: text,
 30→        x: Number.isFinite(parsedX) ? Math.min(Math.max(parsedX, 0), 1) : 0.5,
 31→        y: Number.isFinite(parsedY) ? Math.min(Math.max(parsedY, 0), 1) : 0.5,
 32→        rotation: Number.isFinite(parsedRotation) ? parsedRotation : 0,
 33→        zIndex: Number.isFinite(parsedZIndex) ? parsedZIndex : index,
 34→        fontStyle: typeof snippet.fontStyle === 'string' ? snippet.fontStyle : 'serif',
 35→        scaleX: Number.isFinite(parsedScaleX) && (parsedScaleX === 1 || parsedScaleX === -1) ? parsedScaleX : 1,
 36→        sizeScale: Number.isFinite(parsedSizeScale) ? Math.min(Math.max(parsedSizeScale, 0.6), 2.5) : 1
 37→    };
 38→};
 39→
 40→const normalizeImage = (image, index) => {
 41→    if(!isPlainObject(image)){
 42→        return null;
 43→    }
 44→
 45→    const parsedX = Number(image.x);
 46→    const parsedY = Number(image.y);
 47→    const parsedWidth = Number(image.width);
 48→    const parsedHeight = Number(image.height);
 49→    const parsedRotation = Number(image.rotation);
 50→    const parsedZIndex = Number(image.zIndex);
 51→    const parsedScaleX = Number(image.scaleX);
 52→
 53→    return {
 54→        id: typeof image.id === 'string' && image.id ? image.id : `image-${index + 1}`,
 55→        src: typeof image.src === 'string' ? image.src : '',
 56→        x: Number.isFinite(parsedX) ? Math.min(Math.max(parsedX, 0), 1) : 0.5,
 57→        y: Number.isFinite(parsedY) ? Math.min(Math.max(parsedY, 0), 1) : 0.5,
 58→        width: Number.isFinite(parsedWidth) ? Math.max(0.08, Math.min(parsedWidth, 1)) : 0.28,
 59→        height: Number.isFinite(parsedHeight) ? Math.max(0.08, Math.min(parsedHeight, 1.2)) : 0.22,
 60→        rotation: Number.isFinite(parsedRotation) ? parsedRotation : 0,
 61→        zIndex: Number.isFinite(parsedZIndex) ? parsedZIndex : index,
 62→        scaleX: Number.isFinite(parsedScaleX) && (parsedScaleX === 1 || parsedScaleX === -1) ? parsedScaleX : 1
 63→    };
 64→};
 65→
 66→export const parseCanvasDoc = (rawCanvasDoc) => {
 67→    if(!rawCanvasDoc){
 68→        return {...DEFAULT_CANVAS_DOC};
 69→    }
 70→
 71→    try {
 72→        const parsed = typeof rawCanvasDoc === 'string' ? JSON.parse(rawCanvasDoc) : rawCanvasDoc;
 73→        if(!isPlainObject(parsed)){
 74→            return {...DEFAULT_CANVAS_DOC};
 75→        }
 76→
 77→        const snippets = Array.isArray(parsed.snippets)
 78→            ? parsed.snippets
 79→                .map((snippet, index) => normalizeSnippet(snippet, index))
 80→                .filter(Boolean)
 81→            : [];
 82→        const images = Array.isArray(parsed.images)
 83→            ? parsed.images
 84→                .map((image, index) => normalizeImage(image, index))
 85→                .filter(Boolean)
 86→            : [];
 87→
 88→        return {
 89→            version: 1,
 90→            meta: {
 91→                aspectRatio: parsed?.meta?.aspectRatio === '4:5' ? '4:5' : '1:1',
