213→        remixSourceJournalId
214→        && typeof remixSourceJournalId === 'string'
215→        && remixSourceJournalId.trim()
216→    );
217→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
218→    let payload = {
219→        user_id: userId,
220→        title: trimmedTitle,
221→        post_type: resolvedPostType
222→    };
223→
224→    if(resolvedPostType === POST_TYPE_CANVAS){
225→        let parsedCanvasDoc = null;
226→        try {
227→            parsedCanvasDoc = parseCanvasDocInput(canvasDocInput);
228→        } catch (error) {
229→            console.error('invalid canvas doc on insert:', error?.message || error);
230→            throw {status: 400, error: 'invalid canvas_doc'};
