157→const listMediaChunkForBucket = async(bucket, userId, offset, limit) => {
158→    const folderPath = `user_id_${userId}`;
159→
160→    const {data: bucketItems, error: bucketError} = await supabase.storage
161→        .from(bucket)
162→        .list(folderPath, {
163→            limit: limit,
164→            offset: offset,
165→            sortBy: {column: 'name', order: 'desc'}
166→        });
167→
168→    if(bucketError){
169→        return {
170→            bucket: bucket,
171→            nextOffset: offset,
172→            exhausted: true,
173→            items: [],
174→            error: bucketError.message
175→        };
176→    }
177→
178→    const listedItems = Array.isArray(bucketItems) ? bucketItems : [];
179→    const normalizedItems = listedItems
180→        .filter((item) => item?.name && hasSupportedMediaExtension(item.name))
181→        .map((item) => {
182→            const path = `${folderPath}/${item.name}`;
183→            const createdAt = item.created_at || item.updated_at || null;
184→
185→            return {
186→                bucket: bucket,
187→                path: path,
188→                name: item.name,
189→                createdAt: createdAt,
190→                timestamp: parseMediaTimestamp(item)
191→            };
192→        });
193→
194→    return {
195→        bucket: bucket,
196→        nextOffset: offset + listedItems.length,
197→        exhausted: listedItems.length < limit,
198→        items: normalizedItems,
199→        error: null
200→    };
201→};
